function solve(s) {
    const n = s.length;

    // A string is "cohesive" if it does not contain "011" or "110" as a subsequence.
    // Let's analyze the structure of strings that avoid these subsequences.

    // Avoids "011": This means we cannot have a '0' followed by two '1's.
    // Avoids "110": This means we cannot have two '1's followed by a '0'.

    // Consider the possible structures of cohesive strings:
    // 1. All '0's: "000..." -> No '1's, so no "011" or "110". Cohesive.
    // 2. All '1's: "111..." -> No '0's, so no "011" or "110". Cohesive.

    // 3. Mixed strings:
    // If the string has both '0's and '1's.
    // If it has a pattern like ...0...11..., it contains "011".
    // If it has a pattern like ...11...0..., it contains "110".

    // This implies that any cohesive string must be structured such that all the '0's appear after all the '1's, OR all the '1's appear after all the '0's, OR it's monochromatic.

    // Case 1: All '0's followed by all '1's (Pattern: 00...011...1)
    // Example: "0011".
    // Subsequences:
    // "011"? Needs 0, then 1, then 1. Yes, if there is at least one '0' and at least two '1's.
    // If we have k zeros and m ones, where k>=1, m>=2.
    // "011" is possible if k>=1 and m>=2. (Take the first 0, and any two 1s).
    // "110"? Needs 1, then 1, then 0. Yes, if there are at least two '1's and one '0'.
    // If we have k>=2, m>=1. (Take any two 1s, and the last 0).

    // If the string is $0^k 1^m$:
    // - If k >= 1 and m >= 2: Contains "011". (0 from $0^k$, two 1s from $1^m$)
    // - If k >= 2 and m >= 1: Contains "110". (Two 1s from $1^m$, 0 from $0^k$)

    // For $0^k 1^m$ to be cohesive:
    // 1. k=0 (All 1s) -> Cohesive
    // 2. m=0 (All 0s) -> Cohesive
    // 3. k=1, m=1 ("01") -> Cohesive.
    // 4. k=1, m=0 ("0") -> Cohesive.
    // 5. k=0, m=1 ("1") -> Cohesive.

    // Let's check the constraints on $0^k 1^m$:
    // If k=1, m=1 ("01"): No "011" (need 2 ones), no "110" (need 2 ones). Cohesive.
    // If k=2, m=1 ("001"): No "011" (need 2 ones), no "110" (need 2 ones). Cohesive.
    // If k=1, m=2 ("011"): Contains "011". NOT cohesive.
    // If k=2, m=2 ("0011"): Contains "011" (0, 1, 1), Contains "110" (1, 1, 0). NOT cohesive.

    // This means that any cohesive string must be either:
    // 1. All '0's ($0^n$)
    // 2. All '1's ($1^n$)
    // 3. A single block of '0's followed by a single block of '1's, where $k \le 1$ OR $m \le 1$.
    //    a. $0^k 1^1$: $k$ zeros followed by one 1. (e.g., "001"). Cohesive.
    //    b. $0^1 1^m$: One 0 followed by $m$ ones. (e.g., "01"). Cohesive if m=1. If m>=2 ("011"), NOT cohesive.
    // Wait, if $m \ge 2$, "011" is a subsequence. So $01^m$ is cohesive only if $m \le 1$.

    // Let's re-evaluate the structure $0^k 1^m$:
    // Subsequences:
    // "011": requires $k \ge 1$ and $m \ge 2$.
    // "110": requires $m \ge 2$ and $k \ge 1$. (Wait, $0^k 1^m$. The 1s come first, 0s last. For "110", we need 1s before 0. This structure $0^k 1^m$ CANNOT have "110" as a subsequence if $k \ge 1, m \ge 1$, because all 1s appear after all 0s).

    // Let's check $0^k 1^m$ again.
    // Subsequences:
    // "011": Yes, if $k \ge 1$ and $m \ge 2$.
    // "110": No, because all 0s appear before all 1s. The pattern requires $1 \to 1 \to 0$.

    // Cohesive condition for $0^k 1^m$:
    // Must NOT have "011".
    // $\implies$ Either $k=0$ (all 1s), or $m < 2$ (i.e., $m=0$ or $m=1$).
    // Possible cohesive structures:
    // 1. $0^n$ (k=n, m=0)
    // 2. $1^n$ (k=0, m=n)
    // 3. $0^k 1$ ($k \ge 1, m=1$)

    // Case 2: All '1's followed by all '0's (Pattern: 11...100...0)
    // Example: "1100".
    // Subsequences:
    // "011": No, because all 1s appear before all 0s. The pattern requires $0 \to 1 \to 1$.
    // "110": Yes, if $m \ge 2$ and $k \ge 1$. (Two 1s from $1^m$, one 0 from $0^k$).

    // Cohesive condition for $1^m 0^k$:
    // Must NOT have "110".
    // $\implies$ Either $m < 2$ (i.e., $m=0$ or $m=1$), or $k=0$ (all 1s).
    // Possible cohesive structures:
    // 1. $0^n$ (m=0, k=n)
    // 2. $1^n$ (m=n, k=0)
    // 3. $1 0^k$ ($m=1, k \ge 1$)

    // Summary of all cohesive structures:
    // A string $s'$ is cohesive if it is one of these forms:
    // A. Monochromatic: $0^n$ or $1^n$.
    // B. $0^k 1$ (k >= 1)
    // C. $1 0^k$ (k >= 1)

    // The problem asks for the minimum flips to achieve *any* cohesive state.

    // We need to calculate:
    // Min_Flips = min(
    //     Cost to make it $0^n$,
    //     Cost to make it $1^n$,
    //     Min_Cost($0^k 1$),
    //     Min_Cost($1 0^k$)
    // )

    // 1. Cost to make it $0^n$: Count of '1's in $s$.
    let cost0 = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === '1') cost0++;
    }

