    let minFlips = Math.min(cost0, cost1);

    // A3: Target $01^{n-1}$
    let costA3 = 0;
    // s[0] must be '0'
    if (s[0] === '1') costA3++;
    // s[i] must be '1' for i > 0
    for (let i = 1; i < n; i++) {
        if (s[i] === '0') costA3++;
    }
    minFlips = Math.min(minFlips, costA3);

    // A4: Target $0^{n-1}1$
    let costA4 = 0;
    // s[i] must be '0' for i < n-1
    for (let i = 0; i < n - 1; i++) {
        if (s[i] === '1') costA4++;
    }
    // s[n-1] must be '1'
    if (s[n - 1] === '0') costA4++;
    minFlips = Math.min(minFlips, costA4);

    // B3: Target $10^{n-1}$
    let costB3 = 0;
    // s[0] must be '1'
    if (s[0] === '0') costB3++;
    // s[i] must be '0' for i > 0
    for (let i = 1; i < n; i++) {
        if (s[i] === '1') costB3++;
    }
    minFlips = Math.min(minFlips, costB3);

    // B4: Target $1^{n-1}0$
    let costB4 = 0;
    // s[i] must be '1' for i < n-1
    for (let i = 0; i < n - 1; i++) {
        if (s[i] === '0') costB4++;
    }
    // s[n-1] must be '0'
    if (s[n - 1] === '1') costB4++;
    minFlips = Math.min(minFlips, costB4);

    return minFlips;
